lessons.solution:
def calculate_distance(vec1, vec2):
    # Simple distance: sum of absolute differences
    return abs(vec1[0] - vec2[0]) + abs(vec1[1] - vec2[1])

query = [0.1, 0.9]  # "Dog"
db = {
    'Cat': [0.2, 0.8],
    'Car': [0.9, -0.1],
    'Fish': [0.3, 0.7]
}

best_match = None
min_distance = float('inf')

for word, vector in db.items():
    dist = calculate_distance(query, vector)
    print(f"Distance to {word}: {dist:.2f}")
    if dist < min_distance:
        min_distance = dist
        best_match = word

print(f"\nMost similar to query: {best_match}")

